import{_ as a,o as s,c as n,ai as o}from"./chunks/framework.CsYGeNYI.js";const u=JSON.parse('{"title":"Gateway Architecture","description":"","frontmatter":{"summary":"WebSocket gateway architecture, components, and client flows","read_when":["Working on gateway protocol, clients, or transports"],"title":"Gateway Architecture"},"headers":[],"relativePath":"concepts/architecture.md","filePath":"concepts/architecture.md","lastUpdated":1771906665000}'),t={name:"concepts/architecture.md"};function i(l,e,c,r,d,p){return s(),n("div",null,[...e[0]||(e[0]=[o(`<h1 id="gateway-architecture" tabindex="-1"><a class="header-anchor" href="#gateway-architecture">#</a> Gateway architecture</h1><p>Last updated: 2026-01-22</p><h2 id="overview" tabindex="-1"><a class="header-anchor" href="#overview">#</a> Overview</h2><ul><li>A single long‑lived <strong>Gateway</strong> owns all messaging surfaces (WhatsApp via Baileys, Telegram via grammY, Slack, Discord, Signal, iMessage, WebChat).</li><li>Control-plane clients (macOS app, CLI, web UI, automations) connect to the Gateway over <strong>WebSocket</strong> on the configured bind host (default <code>127.0.0.1:18789</code>).</li><li><strong>Nodes</strong> (macOS/iOS/Android/headless) also connect over <strong>WebSocket</strong>, but declare <code>role: node</code> with explicit caps/commands.</li><li>One Gateway per host; it is the only place that opens a WhatsApp session.</li><li>A <strong>canvas host</strong> (default <code>18793</code>) serves agent‑editable HTML and A2UI.</li></ul><h2 id="components-and-flows" tabindex="-1"><a class="header-anchor" href="#components-and-flows">#</a> Components and flows</h2><h3 id="gateway-daemon" tabindex="-1"><a class="header-anchor" href="#gateway-daemon">#</a> Gateway (daemon)</h3><ul><li>Maintains provider connections.</li><li>Exposes a typed WS API (requests, responses, server‑push events).</li><li>Validates inbound frames against JSON Schema.</li><li>Emits events like <code>agent</code>, <code>chat</code>, <code>presence</code>, <code>health</code>, <code>heartbeat</code>, <code>cron</code>.</li></ul><h3 id="clients-mac-app-cli-web-admin" tabindex="-1"><a class="header-anchor" href="#clients-mac-app-cli-web-admin">#</a> Clients (mac app / CLI / web admin)</h3><ul><li>One WS connection per client.</li><li>Send requests (<code>health</code>, <code>status</code>, <code>send</code>, <code>agent</code>, <code>system-presence</code>).</li><li>Subscribe to events (<code>tick</code>, <code>agent</code>, <code>presence</code>, <code>shutdown</code>).</li></ul><h3 id="nodes-macos-ios-android-headless" tabindex="-1"><a class="header-anchor" href="#nodes-macos-ios-android-headless">#</a> Nodes (macOS / iOS / Android / headless)</h3><ul><li>Connect to the <strong>same WS server</strong> with <code>role: node</code>.</li><li>Provide a device identity in <code>connect</code>; pairing is <strong>device‑based</strong> (role <code>node</code>) and approval lives in the device pairing store.</li><li>Expose commands like <code>canvas.*</code>, <code>camera.*</code>, <code>screen.record</code>, <code>location.get</code>.</li></ul><p>Protocol details:</p><ul><li><a href="/docs/gateway/protocol">Gateway protocol</a></li></ul><h3 id="webchat" tabindex="-1"><a class="header-anchor" href="#webchat">#</a> WebChat</h3><ul><li>Static UI that uses the Gateway WS API for chat history and sends.</li><li>In remote setups, connects through the same SSH/Tailscale tunnel as other clients.</li></ul><h2 id="connection-lifecycle-single-client" tabindex="-1"><a class="header-anchor" href="#connection-lifecycle-single-client">#</a> Connection lifecycle (single client)</h2><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Client                    Gateway</span></span>
<span class="line"><span>  |                          |</span></span>
<span class="line"><span>  |---- req:connect --------&gt;|</span></span>
<span class="line"><span>  |&lt;------ res (ok) ---------|   (or res error + close)</span></span>
<span class="line"><span>  |   (payload=hello-ok carries snapshot: presence + health)</span></span>
<span class="line"><span>  |                          |</span></span>
<span class="line"><span>  |&lt;------ event:presence ---|</span></span>
<span class="line"><span>  |&lt;------ event:tick -------|</span></span>
<span class="line"><span>  |                          |</span></span>
<span class="line"><span>  |------- req:agent -------&gt;|</span></span>
<span class="line"><span>  |&lt;------ res:agent --------|   (ack: {runId,status:&quot;accepted&quot;})</span></span>
<span class="line"><span>  |&lt;------ event:agent ------|   (streaming)</span></span>
<span class="line"><span>  |&lt;------ res:agent --------|   (final: {runId,status,summary})</span></span>
<span class="line"><span>  |                          |</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br></div></div><h2 id="wire-protocol-summary" tabindex="-1"><a class="header-anchor" href="#wire-protocol-summary">#</a> Wire protocol (summary)</h2><ul><li>Transport: WebSocket, text frames with JSON payloads.</li><li>First frame <strong>must</strong> be <code>connect</code>.</li><li>After handshake: <ul><li>Requests: <code>{type:&quot;req&quot;, id, method, params}</code> → <code>{type:&quot;res&quot;, id, ok, payload|error}</code></li><li>Events: <code>{type:&quot;event&quot;, event, payload, seq?, stateVersion?}</code></li></ul></li><li>If <code>OPENSOUL_GATEWAY_TOKEN</code> (or <code>--token</code>) is set, <code>connect.params.auth.token</code> must match or the socket closes.</li><li>Idempotency keys are required for side‑effecting methods (<code>send</code>, <code>agent</code>) to safely retry; the server keeps a short‑lived dedupe cache.</li><li>Nodes must include <code>role: &quot;node&quot;</code> plus caps/commands/permissions in <code>connect</code>.</li></ul><h2 id="pairing-local-trust" tabindex="-1"><a class="header-anchor" href="#pairing-local-trust">#</a> Pairing + local trust</h2><ul><li>All WS clients (operators + nodes) include a <strong>device identity</strong> on <code>connect</code>.</li><li>New device IDs require pairing approval; the Gateway issues a <strong>device token</strong> for subsequent connects.</li><li><strong>Local</strong> connects (loopback or the gateway host’s own tailnet address) can be auto‑approved to keep same‑host UX smooth.</li><li><strong>Non‑local</strong> connects must sign the <code>connect.challenge</code> nonce and require explicit approval.</li><li>Gateway auth (<code>gateway.auth.*</code>) still applies to <strong>all</strong> connections, local or remote.</li></ul><p>Details: <a href="/docs/gateway/protocol">Gateway protocol</a>, <a href="/docs/channels/pairing">Pairing</a>, <a href="/docs/gateway/security/index">Security</a>.</p><h2 id="protocol-typing-and-codegen" tabindex="-1"><a class="header-anchor" href="#protocol-typing-and-codegen">#</a> Protocol typing and codegen</h2><ul><li>TypeBox schemas define the protocol.</li><li>JSON Schema is generated from those schemas.</li><li>Swift models are generated from the JSON Schema.</li></ul><h2 id="remote-access" tabindex="-1"><a class="header-anchor" href="#remote-access">#</a> Remote access</h2><ul><li><p>Preferred: Tailscale or VPN.</p></li><li><p>Alternative: SSH tunnel</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ssh</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -N</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -L</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> 18789:127.0.0.1:18789</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> user@host</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div></li><li><p>The same handshake + auth token apply over the tunnel.</p></li><li><p>TLS + optional pinning can be enabled for WS in remote setups.</p></li></ul><h2 id="operations-snapshot" tabindex="-1"><a class="header-anchor" href="#operations-snapshot">#</a> Operations snapshot</h2><ul><li>Start: <code>opensoul gateway</code> (foreground, logs to stdout).</li><li>Health: <code>health</code> over WS (also included in <code>hello-ok</code>).</li><li>Supervision: launchd/systemd for auto‑restart.</li></ul><h2 id="invariants" tabindex="-1"><a class="header-anchor" href="#invariants">#</a> Invariants</h2><ul><li>Exactly one Gateway controls a single Baileys session per host.</li><li>Handshake is mandatory; any non‑JSON or non‑connect first frame is a hard close.</li><li>Events are not replayed; clients must refresh on gaps.</li></ul>`,30)])])}const m=a(t,[["render",i]]);export{u as __pageData,m as default};
